const body = $json.body || $json;
const issue = body.issue || body.data || body;
const title = issue.name || issue.title || issue.issue?.name || 'Untitled Plane item';
const description = issue.description_stripped || issue.description || issue.description_html || issue.issue?.description || '';
const priority = issue.priority || issue.issue?.priority || 'unknown';
const state = issue.state_detail?.name || issue.state || issue.issue?.state || 'unknown';
const project = issue.project_detail?.name || issue.project || body.project?.name || 'unknown';
const url = issue.url || issue.issue_url || body.url || '';

const prompt = `You are AI Delivery Assistant. Analyze this new Plane work item. Return concise Russian output with sections: Summary, Risk Level (Low/Medium/High), Blockers, Recommendations.\n\nProject: ${project}\nTitle: ${title}\nPriority: ${priority}\nState: ${state}\nURL: ${url}\nDescription:\n${description}`;

return [{ json: { body, issue, title, project, url, prompt } }];

const source = $items('Build Prompt')[0].json;
const answer = $json.message?.content || $json.response || JSON.stringify($json);
const title = source.title || 'Plane item';
const project = source.project || 'unknown';
const url = source.url ? `\n${source.url}` : '';
const text = `### AI Delivery Assistant\n**Project:** ${project}\n**Item:** ${title}${url}\n\n${answer}`;
return [{ json: { text } }];
